// MsgServer is the server API for Msg service.
type MsgServer interface {
	// UpdateParams defines a (governance) operation for updating the module
	// parameters. The authority defaults to the x/gov module account.
	UpdateParams(context.Context, *MsgUpdateParams) (*MsgUpdateParamsResponse, error)
	// CreateMiner defines the CreateMiner RPC.
	CreateMiner(context.Context, *MsgCreateMiner) (*MsgCreateMinerResponse, error)
	// UpdateMiner defines the UpdateMiner RPC.
	UpdateMiner(context.Context, *MsgUpdateMiner) (*MsgUpdateMinerResponse, error)
	// DeleteMiner defines the DeleteMiner RPC.
	DeleteMiner(context.Context, *MsgDeleteMiner) (*MsgDeleteMinerResponse, error)
	// CreateJob defines the CreateJob RPC.
	CreateJob(context.Context, *MsgCreateJob) (*MsgCreateJobResponse, error)
	// UpdateJob defines the UpdateJob RPC.
	UpdateJob(context.Context, *MsgUpdateJob) (*MsgUpdateJobResponse, error)
	// DeleteJob defines the DeleteJob RPC.
	DeleteJob(context.Context, *MsgDeleteJob) (*MsgDeleteJobResponse, error)
	// CreatePools defines the CreatePools RPC.
	CreatePools(context.Context, *MsgCreatePools) (*MsgCreatePoolsResponse, error)
	// UpdatePools defines the UpdatePools RPC.
	UpdatePools(context.Context, *MsgUpdatePools) (*MsgUpdatePoolsResponse, error)
	// DeletePools defines the DeletePools RPC.
	DeletePools(context.Context, *MsgDeletePools) (*MsgDeletePoolsResponse, error)
	// SettleJob defines the SettleJob RPC.
	SettleJob(context.Context, *MsgSettleJob) (*MsgSettleJobResponse, error)
	// SlashMiner defines the SlashMiner RPC.
	SlashMiner(context.Context, *MsgSlashMiner) (*MsgSlashMinerResponse, error)
	// ClaimSubsidy defines the ClaimSubsidy RPC.
	ClaimSubsidy(context.Context, *MsgClaimSubsidy) (*MsgClaimSubsidyResponse, error)
	// ReportDivergence defines the ReportDivergence RPC.
	ReportDivergence(context.Context, *MsgReportDivergence) (*MsgReportDivergenceResponse, error)
	// RewardTraining defines the RewardTraining RPC.
	RewardTraining(context.Context, *MsgRewardTraining) (*MsgRewardTrainingResponse, error)
	// PayReal defines the PayReal RPC.
	PayReal(context.Context, *MsgPayReal) (*MsgPayRealResponse, error)
	// CreateCommit defines the CreateCommit RPC.
	CreateCommit(context.Context, *MsgCreateCommit) (*MsgCreateCommitResponse, error)
	// UpdateCommit defines the UpdateCommit RPC.
	UpdateCommit(context.Context, *MsgUpdateCommit) (*MsgUpdateCommitResponse, error)
	// DeleteCommit defines the DeleteCommit RPC.
	DeleteCommit(context.Context, *MsgDeleteCommit) (*MsgDeleteCommitResponse, error)
	// FinalizeJob defines the FinalizeJob RPC.
	FinalizeJob(context.Context, *MsgFinalizeJob) (*MsgFinalizeJobResponse, error)
	// SettlePay defines the SettlePay RPC.
	SettlePay(context.Context, *MsgSettlePay) (*MsgSettlePayResponse, error)
	// OpenJob defines the OpenJob RPC.
	OpenJob(context.Context, *MsgOpenJob) (*MsgOpenJobResponse, error)
	// Payout defines the Payout RPC.
	Payout(context.Context, *MsgPayout) (*MsgPayoutResponse, error)
	// VerifySemantic defines the VerifySemantic RPC.
	VerifySemantic(context.Context, *MsgVerifySemantic) (*MsgVerifySemanticResponse, error)
	// CreateBeacon defines the CreateBeacon RPC.
	CreateBeacon(context.Context, *MsgCreateBeacon) (*MsgCreateBeaconResponse, error)
	// UpdateBeacon defines the UpdateBeacon RPC.
	UpdateBeacon(context.Context, *MsgUpdateBeacon) (*MsgUpdateBeaconResponse, error)
	// DeleteBeacon defines the DeleteBeacon RPC.
	DeleteBeacon(context.Context, *MsgDeleteBeacon) (*MsgDeleteBeaconResponse, error)
	// SettleSemantic defines the SettleSemantic RPC.
	SettleSemantic(context.Context, *MsgSettleSemantic) (*MsgSettleSemanticResponse, error)
	// ProveAvailability defines the ProveAvailability RPC (Phase 1b -- disponibilité).
	ProveAvailability(context.Context, *MsgProveAvailability) (*MsgProveAvailabilityResponse, error)
	// SubmitVrfBeacon (CR-10) : pose la graine de comité d'un job depuis une preuve VRF vérifiable.
	SubmitVrfBeacon(context.Context, *MsgSubmitVrfBeacon) (*MsgSubmitVrfBeaconResponse, error)
	// RotateMinerKeys (V6-03) : remplace enc/vrf pubkey d'un mineur sans Delete+Create (préserve Demand/Stake).
	RotateMinerKeys(context.Context, *MsgRotateMinerKeys) (*MsgRotateMinerKeysResponse, error)
	RegisterValidatorVrfKey(context.Context, *MsgRegisterValidatorVrfKey) (*MsgRegisterValidatorVrfKeyResponse, error)
	// DisputeVerdict (INT-1 v0) : conteste le verdict d'un job REGLE (permissionless + bond) -> re-adjudication.
	DisputeVerdict(context.Context, *MsgDisputeVerdict) (*MsgDisputeVerdictResponse, error)
	// ResolveDispute (INT-1 v0 inc.2) : resout une dispute (autorite interim) -> rembourse+recompense ou slash le bond.
	ResolveDispute(context.Context, *MsgResolveDispute) (*MsgResolveDisputeResponse, error)
	// AdjudicateDispute (INT-1 v0 inc.4) : clot une dispute SANS gouvernance (trustless) -> verdict d'un comite
	// FRAIS (re-commits "<job>__redo__<miner>", mineurs hors-origine, MAJORITE DU STAKE). Remplace l'autorite interim.
	AdjudicateDispute(context.Context, *MsgAdjudicateDispute) (*MsgAdjudicateDisputeResponse, error)
}

